// packages/relay-plugin/src/internal/store/task-store.ts
function parseMessage(value) {
  if (!value) {
    return;
  }
  return messageSchema.parse(JSON.parse(value));
}
function parseArtifacts(value) {
  const parsed = JSON.parse(value);
  return parsed.map((artifact) => artifactSchema.parse(artifact));
}

class TaskStore {
  database;
  constructor(location = ":memory:") {
    this.database = openSqliteDatabase(location);
    initializeRelaySchema(this.database);
  }
  createTask(input) {
    const now = Date.now();
    this.database.prepare(`INSERT INTO relay_tasks (
          task_id,
          context_id,
          status,
          request_message_json,
          latest_message_json,
          artifacts_json,
          metadata_json,
          dedupe_key,
          created_at,
          updated_at
        ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`).run(input.taskId, input.contextId ?? null, input.status, JSON.stringify(input.requestMessage), null, JSON.stringify([]), JSON.stringify(input.metadata ?? {}), input.dedupeKey ?? null, now, now);
    return this.getTask(input.taskId);
  }
  getTask(taskId) {
    const row = this.database.prepare(`SELECT * FROM relay_tasks WHERE task_id = ?`).get(taskId);
    if (!row) {
      return;
    }
    return this.hydrate(row);
  }
  getTaskByDedupeKey(dedupeKey) {
    const row = this.database.prepare(`SELECT * FROM relay_tasks WHERE dedupe_key = ?`).get(dedupeKey);
    if (!row) {
      return;
    }
    return this.hydrate(row);
  }
  listActiveTasks() {
    const rows = this.database.prepare(`SELECT * FROM relay_tasks WHERE status NOT IN ('completed', 'failed', 'canceled') ORDER BY updated_at ASC`).all();
    return rows.map((row) => this.hydrate(row));
  }
  updateStatus(taskId, status, latestMessage) {
    const now = Date.now();
    this.database.prepare(`UPDATE relay_tasks SET status = ?, latest_message_json = ?, updated_at = ? WHERE task_id = ?`).run(status, latestMessage ? JSON.stringify(latestMessage) : null, now, taskId);
    return this.requireTask(taskId);
  }
  appendArtifact(taskId, artifact, append = true) {
    const current = this.requireTask(taskId);
    const nextArtifacts = append ? [...current.artifacts, artifact] : [artifact];
    this.database.prepare(`UPDATE relay_tasks SET artifacts_json = ?, updated_at = ? WHERE task_id = ?`).run(JSON.stringify(nextArtifacts), Date.now(), taskId);
    return this.requireTask(taskId);
  }
  mergeMetadata(taskId, patch) {
    const current = this.requireTask(taskId);
    this.database.prepare(`UPDATE relay_tasks SET metadata_json = ?, updated_at = ? WHERE task_id = ?`).run(JSON.stringify({ ...current.metadata, ...patch }), Date.now(), taskId);
    return this.requireTask(taskId);
  }
  cancelTask(taskId) {
    const task2 = this.requireTask(taskId);
    if (!["submitted", "working", "input-required"].includes(task2.status)) {
      throw new Error(`Task ${taskId} is not cancellable from status ${task2.status}.`);
    }
    return this.updateStatus(taskId, "canceled");
  }
  close() {
    this.database.close();
  }
  requireTask(taskId) {
    const task2 = this.getTask(taskId);
    if (!task2) {
      throw new Error(`Task not found: ${taskId}`);
    }
    return task2;
  }
  hydrate(row) {
    const requestMessage = messageSchema.parse(JSON.parse(row.request_message_json));
    const latestMessage = parseMessage(row.latest_message_json);
    const artifacts = parseArtifacts(row.artifacts_json);
    const metadata = JSON.parse(row.metadata_json);
    const baseTask = taskSchema.parse({
      taskId: row.task_id,
      contextId: row.context_id ?? undefined,
      status: row.status,
      latestMessage,
      artifacts,
      history: [requestMessage],
      metadata
    });
    return {
      ...baseTask,
      createdAt: row.created_at,
      updatedAt: row.updated_at,
      dedupeKey: row.dedupe_key ?? undefined
    };
  }
}

// packages/relay-plugin/src/internal/store/team-store.ts
import { randomUUID as randomUUID3 } from "node:crypto";
function createRunId() {
  return `teamrun_${randomUUID3()}`;
}
function serializeEvidence(value) {
  if (value === undefined) {
    return null;
  }
  return JSON.stringify(value);
}
function deserializeEvidence(value) {
  if (!value) {
    return;
  }
  try {
    return JSON.parse(value);
  } catch {
    return value;
  }
}
function aggregateRunStatus(workers, currentStatus) {
  if (["failed", "completed"].includes(currentStatus ?? "")) {
    return currentStatus;
  }
  if (workers.length === 0) {
    return "bootstrapping";
  }
  if (workers.some((worker) => worker.status === "failed")) {
    return "failed";
  }
  if (workers.every((worker) => worker.status === "completed")) {
    return "completed";
  }
  if (workers.some((worker) => worker.status === "blocked")) {
    return "blocked";
  }
  if (workers.some((worker) => worker.status === "in_progress")) {
    return "in_progress";
  }
  if (workers.every((worker) => ["ready", "completed"].includes(worker.status))) {
    return "ready";
  }
  if (workers.some((worker) => ["created", "bootstrapped", "joined"].includes(worker.status))) {
    return "waiting";
  }
  return "bootstrapping";
}

class TeamStore {
  database;
  constructor(location = ":memory:") {
    this.database = openSqliteDatabase(location);
    initializeRelaySchema(this.database);
  }
  createRun(input) {
    const now = Date.now();
    const runId = createRunId();
    this.database.prepare(`INSERT INTO relay_team_runs (run_id, manager_session_id, room_code, task, status, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?)`).run(runId, input.managerSessionID, input.roomCode, input.task, "bootstrapping", now, now);
    return this.getRun(runId);
  }
  addWorker(input) {
    const now = Date.now();
    this.database.prepare(`
        INSERT INTO relay_team_workers (run_id, session_id, role, alias, title, status, last_note, workflow_source, workflow_phase, progress, evidence_json, created_at, joined_at, ready_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
      `).run(input.runId, input.sessionID, input.role, input.alias, input.title, input.status ?? "created", input.lastNote ?? null, input.workflowSource ?? null, input.workflowPhase ?? null, input.progress ?? null, serializeEvidence(input.evidence), now, null, null, now);
    this.refreshRunStatus(input.runId);
    return this.requireWorker(input.runId, input.sessionID);
  }
  getRun(runId) {
    const row = this.database.prepare(`SELECT * FROM relay_team_runs WHERE run_id = ?`).get(runId);
    return row ? this.hydrateRun(row) : undefined;
  }
  getRunByRoomCode(roomCode) {
    const row = this.database.prepare(`SELECT * FROM relay_team_runs WHERE room_code = ?`).get(roomCode);
    return row ? this.hydrateRun(row) : undefined;
  }
  getRunForSession(sessionID, roomCode, runId) {
    if (runId) {
      return this.getRun(runId);
    }
    const byManager = this.database.prepare(`
        SELECT * FROM relay_team_runs
        WHERE manager_session_id = ?
          AND (? IS NULL OR room_code = ?)
        ORDER BY updated_at DESC
        LIMIT 1
      `).get(sessionID, roomCode ?? null, roomCode ?? null);
    if (byManager) {
      return this.hydrateRun(byManager);
    }
    const byWorker = this.findWorkerRow(sessionID, roomCode);
    return byWorker ? this.getRun(byWorker.run_id) : undefined;
  }
  listWorkers(runId) {
    const rows = this.database.prepare(`SELECT * FROM relay_team_workers WHERE run_id = ? ORDER BY created_at ASC`).all(runId);
    return rows.map((row) => this.hydrateWorker(row));
  }
  markWorkerBootstrapped(sessionID) {
    return this.updateWorkerBySession(sessionID, undefined, (worker) => ({
      status: ["created", "bootstrapped"].includes(worker.status) ? "bootstrapped" : worker.status,
      lastNote: "bootstrap prompt submitted"
    }));
  }
  markWorkerJoined(sessionID, roomCode, alias) {
    return this.updateWorkerBySession(sessionID, roomCode, (worker) => ({
      alias: alias?.trim() || worker.alias,
      status: ["created", "bootstrapped", "joined"].includes(worker.status) ? "joined" : worker.status,
      joinedAt: worker.joinedAt ?? Date.now(),
      lastNote: "joined relay room"
    }));
  }
  markWorkerSignal(sessionID, roomCode, input) {
    return this.updateWorkerBySession(sessionID, roomCode, (worker) => ({
      status: input.status,
      readyAt: input.ready ? worker.readyAt ?? Date.now() : worker.readyAt,
      lastNote: input.note ?? worker.lastNote,
      workflowSource: input.source ?? worker.workflowSource,
      workflowPhase: input.phase ?? worker.workflowPhase,
      progress: input.progress ?? worker.progress,
      evidence: input.evidence ?? worker.evidence
    }));
  }
  markWorkerFailed(sessionID, errorMessage, roomCode) {
    return this.updateWorkerBySession(sessionID, roomCode, () => ({
      status: "failed",
      lastNote: errorMessage
    }));
  }
  markRunFailed(runId) {
    this.database.prepare(`UPDATE relay_team_runs SET status = ?, updated_at = ? WHERE run_id = ?`).run("failed", Date.now(), runId);
    return this.getRun(runId);
  }
  close() {
    this.database.close();
  }
  refreshRunStatus(runId) {
    const current = this.getRun(runId);
    if (!current) {
      throw new Error(`Team run not found: ${runId}`);
    }
    const nextStatus = aggregateRunStatus(this.listWorkers(runId), current.status);
    this.database.prepare(`UPDATE relay_team_runs SET status = ?, updated_at = ? WHERE run_id = ?`).run(nextStatus, Date.now(), runId);
    return this.getRun(runId);
  }
  requireWorker(runId, sessionID) {
    const row = this.database.prepare(`SELECT * FROM relay_team_workers WHERE run_id = ? AND session_id = ?`).get(runId, sessionID);
    if (!row) {
      throw new Error(`Team worker not found: ${sessionID} in ${runId}`);
    }
    return this.hydrateWorker(row);
  }
  updateWorkerBySession(sessionID, roomCode, mutate) {
    const row = this.findWorkerRow(sessionID, roomCode);
    if (!row) {
      return;
    }
    const worker = this.hydrateWorker(row);
    const patch = mutate(worker);
    const now = Date.now();
    this.database.prepare(`
        UPDATE relay_team_workers
        SET alias = ?, status = ?, last_note = ?, workflow_source = ?, workflow_phase = ?, progress = ?, evidence_json = ?, joined_at = ?, ready_at = ?, updated_at = ?
        WHERE run_id = ? AND session_id = ?
      `).run(patch.alias ?? worker.alias, patch.status ?? worker.status, patch.lastNote ?? worker.lastNote ?? null, patch.workflowSource ?? worker.workflowSource ?? null, patch.workflowPhase ?? worker.workflowPhase ?? null, patch.progress ?? worker.progress ?? null, serializeEvidence(patch.evidence ?? worker.evidence), patch.joinedAt ?? worker.joinedAt ?? null, patch.readyAt ?? worker.readyAt ?? null, now, worker.runId, worker.sessionID);
    this.refreshRunStatus(worker.runId);
    return this.requireWorker(worker.runId, worker.sessionID);
  }
  findWorkerRow(sessionID, roomCode) {
    return this.database.prepare(`
        SELECT w.*, r.room_code, r.manager_session_id, r.status as run_status
        FROM relay_team_workers w
        JOIN relay_team_runs r ON r.run_id = w.run_id
        WHERE w.session_id = ?
          AND (? IS NULL OR r.room_code = ?)
        ORDER BY w.updated_at DESC
        LIMIT 1
      `).get(sessionID, roomCode ?? null, roomCode ?? null);
  }
  hydrateRun(row) {
    return {
      runId: row.run_id,
      managerSessionID: row.manager_session_id,
      roomCode: row.room_code,
      task: row.task,
      status: row.status,
      createdAt: row.created_at,
      updatedAt: row.updated_at
    };
  }
  hydrateWorker(row) {
    return {
      runId: row.run_id,
      sessionID: row.session_id,
      role: row.role,
      alias: row.alias,
      title: row.title,
      status: row.status,
      lastNote: row.last_note ?? undefined,
      workflowSource: row.workflow_source ?? undefined,
      workflowPhase: row.workflow_phase ?? undefined,
      progress: row.progress ?? undefined,
      evidence: deserializeEvidence(row.evidence_json),
      createdAt: row.created_at,
      joinedAt: row.joined_at ?? undefined,
      readyAt: row.ready_at ?? undefined,
      updatedAt: row.updated_at
    };
  }
}

// packages/relay-plugin/src/internal/store/thread-store.ts
import { randomUUID as randomUUID4 } from "node:crypto";
function createThreadId() {
  return `thread_${randomUUID4()}`;
}
function createDirectKey(roomCode, sessionIDs) {
  return `${roomCode}:${[...new Set(sessionIDs)].sort().join(":")}`;
}

class ThreadStore {
  database;
  constructor(location = ":memory:") {
    this.database = openSqliteDatabase(location);
    initializeRelaySchema(this.database);
  }
  ensureDirectThread(roomCode, participantSessionIDs, createdBySessionID) {
    const directKey = createDirectKey(roomCode, participantSessionIDs);
    const existing = this.getThreadByDirectKey(directKey);
    if (existing) {
      return existing;
    }
    return this.createThread({
      roomCode,
      kind: "direct",
      directKey,
      createdBySessionID,
      participantSessionIDs
    });
  }
  ensureGroupThread(roomCode, participantSessionIDs, createdBySessionID, title = "room-main") {
    const existing = this.getThreadByKindAndTitle(roomCode, "group", title);
    if (existing) {
      this.addParticipants(existing.threadId, participantSessionIDs);
      return this.getThread(existing.threadId);
    }
    return this.createThread({
      roomCode,
      kind: "group",
      title,
      createdBySessionID,
      participantSessionIDs
    });
  }
  createGroupThread(roomCode, participantSessionIDs, createdBySessionID, title) {
    return this.createThread({
      roomCode,
      kind: "group",
      title,
      createdBySessionID,
      participantSessionIDs
    });
  }
  getThread(threadId) {
    const row = this.database.prepare(`SELECT * FROM relay_threads WHERE thread_id = ?`).get(threadId);
    return row ? this.hydrate(row) : undefined;
  }
  getThreadByDirectKey(directKey) {
    const row = this.database.prepare(`SELECT * FROM relay_threads WHERE direct_key = ?`).get(directKey);
    return row ? this.hydrate(row) : undefined;
  }
  getThreadByKindAndTitle(roomCode, kind, title) {
    const row = this.database.prepare(`SELECT * FROM relay_threads WHERE room_code = ? AND kind = ? AND title = ? LIMIT 1`).get(roomCode, kind, title);
    return row ? this.hydrate(row) : undefined;
  }
  listThreadsForRoom(roomCode) {
    const rows = this.database.prepare(`SELECT * FROM relay_threads WHERE room_code = ? ORDER BY updated_at ASC`).all(roomCode);
    return rows.map((row) => this.hydrate(row));
  }
  listThreadsForSession(sessionID) {
    const rows = this.database.prepare(`
        SELECT t.*, p.thread_id as participant_thread_id, p.session_id, p.last_read_seq, p.last_notified_seq, p.joined_at, p.updated_at as participant_updated_at
        FROM relay_threads t
        JOIN relay_thread_participants p ON p.thread_id = t.thread_id
        WHERE p.session_id = ?
        ORDER BY t.updated_at ASC
      `).all(sessionID);
    return rows.map((row) => ({
      ...this.hydrate(row),
      participant: {
        threadId: row.participant_thread_id,
        sessionID: row.session_id,
        lastReadSeq: row.last_read_seq,
        lastNotifiedSeq: row.last_notified_seq,
        joinedAt: row.joined_at,
        updatedAt: row.participant_updated_at
      }
    }));
  }
  listParticipants(threadId) {
    const rows = this.database.prepare(`SELECT * FROM relay_thread_participants WHERE thread_id = ? ORDER BY joined_at ASC`).all(threadId);
    return rows.map((row) => this.hydrateParticipant(row));
  }
  getParticipant(threadId, sessionID) {
    const row = this.database.prepare(`SELECT * FROM relay_thread_participants WHERE thread_id = ? AND session_id = ?`).get(threadId, sessionID);
    return row ? this.hydrateParticipant(row) : undefined;
  }
  addParticipants(threadId, sessionIDs) {
    const now = Date.now();
    const uniqueSessionIDs = [...new Set(sessionIDs)];
    for (const sessionID of uniqueSessionIDs) {
      this.database.prepare(`
          INSERT INTO relay_thread_participants (thread_id, session_id, last_read_seq, last_notified_seq, joined_at, updated_at)
          VALUES (?, ?, 0, 0, ?, ?)
          ON CONFLICT(thread_id, session_id) DO NOTHING
        `).run(threadId, sessionID, now, now);
    }
    this.touchThread(threadId);
  }
  markRead(threadId, sessionID, seq) {
    const now = Date.now();
    this.database.prepare(`UPDATE relay_thread_participants SET last_read_seq = MAX(last_read_seq, ?), updated_at = ? WHERE thread_id = ? AND session_id = ?`).run(seq, now, threadId, sessionID);
    return this.requireParticipant(threadId, sessionID);
  }
  markNotified(threadId, sessionID, seq) {
    const now = Date.now();
    this.database.prepare(`UPDATE relay_thread_participants SET last_notified_seq = MAX(last_notified_seq, ?), updated_at = ? WHERE thread_id = ? AND session_id = ?`).run(seq, now, threadId, sessionID);
    return this.requireParticipant(threadId, sessionID);
  }
  touchThread(threadId) {
    this.database.prepare(`UPDATE relay_threads SET updated_at = ? WHERE thread_id = ?`).run(Date.now(), threadId);
  }
  close() {
    this.database.close();
  }
  createThread(input) {
    const now = Date.now();
    const threadId = createThreadId();
    const uniqueParticipants = [...new Set(input.participantSessionIDs)];
    this.database.prepare(`INSERT INTO relay_threads (thread_id, room_code, kind, title, direct_key, created_by_session_id, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?, ?, ?)`).run(threadId, input.roomCode, input.kind, input.title ?? null, input.directKey ?? null, input.createdBySessionID, now, now);
    for (const sessionID of uniqueParticipants) {
      this.database.prepare(`INSERT INTO relay_thread_participants (thread_id, session_id, last_read_seq, last_notified_seq, joined_at, updated_at) VALUES (?, ?, 0, 0, ?, ?)`).run(threadId, sessionID, now, now);
    }
    return this.getThread(threadId);
  }
  requireParticipant(threadId, sessionID) {
    const participant = this.getParticipant(threadId, sessionID);
    if (!participant) {
      throw new Error(`Participant ${sessionID} is not in thread ${threadId}.`);
    }
    return participant;
  }
  hydrate(row) {
    return {
      threadId: row.thread_id,
      roomCode: row.room_code,
      kind: row.kind,
      title: row.title ?? undefined,
      directKey: row.direct_key ?? undefined,
      createdBySessionID: row.created_by_session_id,
      createdAt: row.created_at,
      updatedAt: row.updated_at
    };
  }
  hydrateParticipant(row) {
    return {
      threadId: row.thread_id,
      sessionID: row.session_id,
      lastReadSeq: row.last_read_seq,
      lastNotifiedSeq: row.last_notified_seq,
      joinedAt: row.joined_at,
      updatedAt: row.updated_at
    };
  }
}

// packages/relay-plugin/src/runtime/prompt-preamble.ts
