// packages/relay-plugin/src/runtime/loop-guard.ts
class LoopGuard {
  windowMs;
  seen = new Map;
  constructor(windowMs = 5 * 60 * 1000) {
    this.windowMs = windowMs;
  }
  remember(key, taskId, now = Date.now()) {
    const existing = this.seen.get(key);
    if (existing && now - existing.timestamp <= this.windowMs) {
      return {
        duplicate: true,
        existingTaskId: existing.taskId
      };
    }
    this.seen.set(key, { taskId, timestamp: now });
    return { duplicate: false };
  }
}

